(function() {
  'use strict';

  var PROCESSED = 'data-ba-dl';
  var HASH_ATTR = 'data-ba-dl-hash';
  var VERSION = '1.1.0';

  // Clean up previous instance for SPA re-injection
  if (window.__igDlCleanup) {
    try { window.__igDlCleanup(); } catch(e) {}
  }

  // Inject styles once
  if (!document.getElementById('ba-ig-dl-styles')) {
    var style = document.createElement('style');
    style.id = 'ba-ig-dl-styles';
    style.textContent = [
      /* Toolbar container */
      '.ba-dl-bar{display:flex;flex-wrap:wrap;gap:6px;padding:8px 12px;align-items:center;font-family:-apple-system,BlinkMacSystemFont,"Segoe UI",Roboto,Helvetica,Arial,sans-serif}',
      /* Label chip */
      '.ba-dl-label{display:inline-flex;align-items:center;gap:3px;font-size:12px;font-weight:600;color:#8e8e8e;text-transform:uppercase;letter-spacing:.5px;margin-right:2px;user-select:none}',
      '.ba-dl-label svg{width:14px;height:14px;fill:#8e8e8e}',
      /* Button group for each media item */
      '.ba-dl-group{display:inline-flex;align-items:center;border-radius:8px;overflow:hidden;box-shadow:0 1px 3px rgba(0,0,0,.12)}',
      /* Base button */
      '.ba-dl-btn{display:inline-flex;align-items:center;gap:4px;padding:7px 12px;font-size:13px;font-weight:600;color:#fff;border:none;cursor:pointer;font-family:inherit;transition:background .15s,opacity .15s;line-height:1;white-space:nowrap}',
      '.ba-dl-btn:active{opacity:.8}',
      '.ba-dl-btn svg{width:13px;height:13px;fill:currentColor;flex-shrink:0}',
      /* Download button — blue */
      '.ba-dl-btn--dl{background:#0095f6}',
      '.ba-dl-btn--dl:hover{background:#1877f2}',
      /* Open in tab — dark (images only) */
      '.ba-dl-btn--open{background:#363636;border-left:1px solid rgba(255,255,255,.15)}',
      '.ba-dl-btn--open:hover{background:#4a4a4a}',
      /* Numbered badge for carousel items */
      '.ba-dl-num{display:inline-flex;align-items:center;justify-content:center;width:18px;height:18px;border-radius:50%;background:rgba(255,255,255,.25);font-size:11px;font-weight:700;color:#fff;flex-shrink:0}',
      /* Story overlay positioning */
      '.ba-dl-bar--story{position:absolute;bottom:60px;left:50%;transform:translateX(-50%);z-index:9999;background:rgba(0,0,0,.55);backdrop-filter:blur(8px);-webkit-backdrop-filter:blur(8px);border-radius:12px;padding:6px 10px}',
      '.ba-dl-bar--story .ba-dl-btn--dl{background:rgba(255,255,255,.2)}',
      '.ba-dl-bar--story .ba-dl-btn--dl:hover{background:rgba(255,255,255,.35)}',
      '.ba-dl-bar--story .ba-dl-label{color:rgba(255,255,255,.7)}',
      '.ba-dl-bar--story .ba-dl-label svg{fill:rgba(255,255,255,.7)}',
      /* Divider between photo/video sections */
      '.ba-dl-sep{width:1px;height:20px;background:#dbdbdb;margin:0 4px}'
    ].join('\n');
    document.head.appendChild(style);
  }

  var DL_ICON = '<svg viewBox="0 0 24 24"><path d="M12 15.575l-4.95-4.95 1.414-1.414L11 11.747V3h2v8.747l2.536-2.536 1.414 1.414L12 15.575zM5 19h14v-4h2v5a1 1 0 01-1 1H4a1 1 0 01-1-1v-5h2v4z"/></svg>';
  var OPEN_ICON = '<svg viewBox="0 0 24 24"><path d="M10 6v2H5v11h11v-5h2v6a1 1 0 01-1 1H4a1 1 0 01-1-1V7a1 1 0 011-1h6zm11-3v8h-2V6.413l-7.793 7.794-1.414-1.414L17.585 5H13V3h8z"/></svg>';
  var PHOTO_ICON = '<svg viewBox="0 0 24 24"><path d="M5 3h14a2 2 0 012 2v14a2 2 0 01-2 2H5a2 2 0 01-2-2V5a2 2 0 012-2zm0 2v10.586l4-4 3 3 4-4 4 4V5H5zm0 14h14v-1.414l-4-4-4 4-3-3-3 3V19zM8.5 11A1.5 1.5 0 118.5 8a1.5 1.5 0 010 3z"/></svg>';
  var VIDEO_ICON = '<svg viewBox="0 0 24 24"><path d="M3 3.993C3 3.445 3.445 3 3.993 3h16.014c.548 0 .993.445.993.993v16.014a.994.994 0 01-.993.993H3.993A.994.994 0 013 20.007V3.993zM5 5v14h14V5H5zm4.622 3.415l4.879 3.252a.4.4 0 010 .666l-4.879 3.252A.4.4 0 019 15.319V8.681a.4.4 0 01.622-.266z"/></svg>';

  function makeDownloadBtn(url, label, isVideo) {
    var btn = document.createElement('button');
    btn.className = 'ba-dl-btn ba-dl-btn--dl';
    btn.title = 'Download ' + label;
    btn.innerHTML = DL_ICON + ' <span>' + label + '</span>';
    btn.addEventListener('click', function(e) {
      e.preventDefault();
      e.stopPropagation();
      // Use fetch + blob for reliable download
      fetch(url, { mode: 'cors', credentials: 'include' })
        .then(function(r) { return r.blob(); })
        .then(function(blob) {
          var blobUrl = URL.createObjectURL(blob);
          var a = document.createElement('a');
          a.href = blobUrl;
          a.download = 'instagram_' + Date.now() + (isVideo ? '.mp4' : '.jpg');
          document.body.appendChild(a);
          a.click();
          a.remove();
          setTimeout(function() { URL.revokeObjectURL(blobUrl); }, 1000);
        })
        .catch(function() {
          // Fallback: direct link
          var a = document.createElement('a');
          a.href = url;
          a.download = 'instagram_' + Date.now() + (isVideo ? '.mp4' : '.jpg');
          a.target = '_blank';
          a.rel = 'noopener';
          document.body.appendChild(a);
          a.click();
          a.remove();
        });
    });
    return btn;
  }

  function makeOpenBtn(url) {
    var btn = document.createElement('button');
    btn.className = 'ba-dl-btn ba-dl-btn--open';
    btn.title = 'Open in new tab';
    btn.innerHTML = OPEN_ICON;
    btn.addEventListener('click', function(e) {
      e.preventDefault();
      e.stopPropagation();
      window.open(url, '_blank');
    });
    return btn;
  }

  function buildMediaGroup(url, label, isVideo) {
    var group = document.createElement('span');
    group.className = 'ba-dl-group';
    group.appendChild(makeDownloadBtn(url, label, isVideo));
    // Only add Open button for images — video URLs are authenticated and fail in new tabs
    if (!isVideo) {
      group.appendChild(makeOpenBtn(url));
    }
    return group;
  }

  function getMediaFromArticle(article) {
    var result = { images: [], videos: [] };
    article.querySelectorAll('video[src], video source[src]').forEach(function(v) {
      var src = v.src || v.getAttribute('src');
      if (src && result.videos.indexOf(src) === -1) result.videos.push(src);
    });
    article.querySelectorAll('img[srcset], img[src]').forEach(function(img) {
      if (img.width < 50 || img.height < 50) return;
      if (img.closest('header')) return;
      var srcset = img.getAttribute('srcset');
      var bestSrc = '';
      if (srcset) {
        var parts = srcset.split(',').map(function(s) { return s.trim(); });
        bestSrc = parts[parts.length - 1].split(' ')[0];
      } else {
        bestSrc = img.src;
      }
      if (bestSrc && bestSrc.indexOf('s150x150') === -1 && result.images.indexOf(bestSrc) === -1) {
        result.images.push(bestSrc);
      }
    });
    return result;
  }

  function hashMedia(media) {
    return media.images.concat(media.videos).join('|');
  }

  function buildBar(media, extraClass) {
    var bar = document.createElement('div');
    bar.className = 'ba-dl-bar' + (extraClass ? ' ' + extraClass : '');

    if (media.images.length > 0) {
      var photoLabel = document.createElement('span');
      photoLabel.className = 'ba-dl-label';
      photoLabel.innerHTML = PHOTO_ICON + (media.images.length > 1 ? ' Photos' : ' Photo');
      bar.appendChild(photoLabel);
      media.images.forEach(function(url, idx) {
        var label = media.images.length > 1 ? '<span class="ba-dl-num">' + (idx + 1) + '</span>' : 'Download';
        bar.appendChild(buildMediaGroup(url, label, false));
      });
    }

    if (media.images.length > 0 && media.videos.length > 0) {
      var sep = document.createElement('span');
      sep.className = 'ba-dl-sep';
      bar.appendChild(sep);
    }

    if (media.videos.length > 0) {
      var videoLabel = document.createElement('span');
      videoLabel.className = 'ba-dl-label';
      videoLabel.innerHTML = VIDEO_ICON + (media.videos.length > 1 ? ' Videos' : ' Video');
      bar.appendChild(videoLabel);
      media.videos.forEach(function(url, idx) {
        var label = media.videos.length > 1 ? '<span class="ba-dl-num">' + (idx + 1) + '</span>' : 'Download';
        bar.appendChild(buildMediaGroup(url, label, true));
      });
    }

    return bar;
  }

  function processPost(article) {
    var media = getMediaFromArticle(article);
    if (media.images.length === 0 && media.videos.length === 0) return;

    var hash = hashMedia(media);
    // Skip if already processed with the same media hash (carousel unchanged)
    if (article.getAttribute(HASH_ATTR) === hash) return;

    // Remove old bar if media changed (carousel slide)
    var oldBar = article.querySelector('.ba-dl-bar');
    if (oldBar) oldBar.remove();

    article.setAttribute(PROCESSED, 'true');
    article.setAttribute(HASH_ATTR, hash);

    var bar = buildBar(media, '');
    var section = article.querySelector('section');
    if (section) {
      section.parentElement.insertBefore(bar, section);
    } else {
      article.appendChild(bar);
    }
  }

  function processStories() {
    // Video stories
    var storyVideo = document.querySelector('[role="presentation"] video[src], [role="dialog"] video[src]');
    if (storyVideo) {
      var parent = storyVideo.closest('[role="presentation"]') || storyVideo.closest('[role="dialog"]');
      if (parent) {
        var hash = 'v:' + storyVideo.src;
        if (parent.getAttribute(HASH_ATTR) !== hash) {
          var oldBar = parent.querySelector('.ba-dl-bar');
          if (oldBar) oldBar.remove();
          parent.setAttribute(HASH_ATTR, hash);
          parent.setAttribute(PROCESSED, 'true');
          var bar = buildBar({ images: [], videos: [storyVideo.src] }, 'ba-dl-bar--story');
          parent.style.position = 'relative';
          parent.appendChild(bar);
        }
      }
    }

    // Photo stories
    var storyImg = document.querySelector('[role="presentation"] img[srcset], [role="dialog"] img[decoding="sync"]');
    if (storyImg) {
      var srcset = storyImg.getAttribute('srcset');
      var bestSrc = storyImg.src;
      if (srcset) {
        var parts = srcset.split(',').map(function(s) { return s.trim(); });
        bestSrc = parts[parts.length - 1].split(' ')[0];
      }
      var imgParent = storyImg.closest('[role="presentation"]') || storyImg.closest('[role="dialog"]');
      if (imgParent) {
        var imgHash = 'i:' + bestSrc;
        if (imgParent.getAttribute(HASH_ATTR) !== imgHash) {
          var oldBar2 = imgParent.querySelector('.ba-dl-bar');
          if (oldBar2) oldBar2.remove();
          imgParent.setAttribute(HASH_ATTR, imgHash);
          imgParent.setAttribute(PROCESSED, 'true');
          var bar2 = buildBar({ images: [bestSrc], videos: [] }, 'ba-dl-bar--story');
          imgParent.style.position = 'relative';
          imgParent.appendChild(bar2);
        }
      }
    }
  }

  function processProfilePicture() {
    var header = document.querySelector('header');
    if (!header) return;

    var avatar = header.querySelector('img[alt*="profile picture"], img[data-testid="user-avatar"]');
    if (!avatar) return;

    var src = avatar.src;
    if (!src) return;
    var fullSrc = src.replace(/\/s\d+x\d+\//, '/').replace(/\/c\d+\.\d+\.\d+\.\d+\//, '/');

    var hash = 'p:' + fullSrc;
    if (header.getAttribute(HASH_ATTR) === hash) return;

    var oldBar = header.querySelector('.ba-dl-bar');
    if (oldBar) oldBar.remove();

    header.setAttribute(HASH_ATTR, hash);
    header.setAttribute(PROCESSED, 'true');

    var bar = buildBar({ images: [fullSrc], videos: [] }, '');
    var avatarParent = avatar.closest('span') || avatar.parentElement;
    if (avatarParent && avatarParent.parentElement) {
      avatarParent.parentElement.appendChild(bar);
    }
  }

  function processAll() {
    document.querySelectorAll('article').forEach(processPost);
    processStories();
    processProfilePicture();
  }

  // Run immediately
  processAll();

  // Debounced MutationObserver to avoid excessive processing
  var debounceTimer = null;
  var observer = new MutationObserver(function() {
    if (debounceTimer) clearTimeout(debounceTimer);
    debounceTimer = setTimeout(processAll, 300);
  });
  observer.observe(document.body, { childList: true, subtree: true });

  // SPA navigation detection — re-process when URL changes
  var lastUrl = location.href;
  var urlCheckInterval = setInterval(function() {
    if (location.href !== lastUrl) {
      lastUrl = location.href;
      // Clear processed state on navigation so new page content gets buttons
      document.querySelectorAll('[' + HASH_ATTR + ']').forEach(function(el) {
        el.removeAttribute(HASH_ATTR);
        el.removeAttribute(PROCESSED);
        var bar = el.querySelector('.ba-dl-bar');
        if (bar) bar.remove();
      });
      setTimeout(processAll, 500);
    }
  }, 1000);

  // Cleanup function for re-injection
  window.__igDlCleanup = function() {
    observer.disconnect();
    if (debounceTimer) clearTimeout(debounceTimer);
    clearInterval(urlCheckInterval);
    document.querySelectorAll('.ba-dl-bar').forEach(function(el) { el.remove(); });
    document.querySelectorAll('[' + HASH_ATTR + ']').forEach(function(el) {
      el.removeAttribute(HASH_ATTR);
      el.removeAttribute(PROCESSED);
    });
  };

  console.log('[Instagram Download Button v' + VERSION + '] Active');
})();
